export type BoundRequestMethod = Extract<
  keyof MethodParamsByName,
  ClientRequestMethod | ServerRequestMethod | GollemExtensionMethod
>;
export type BoundNotificationMethod = Extract<
  keyof MethodParamsByName,
  ServerNotificationMethod | ClientNotificationMethod
>;

export type ParamsFor<M extends keyof MethodParamsByName> = MethodParamsByName[M];
export type ResultFor<M extends keyof MethodResultsByName> = MethodResultsByName[M];

export type BoundRequest<M extends BoundRequestMethod> =
  MethodParamsByName[M] extends undefined
    ? { "id": RequestID; "method": M; "params"?: never }
    : { "id": RequestID; "method": M; "params": MethodParamsByName[M] };

export type BoundNotification<M extends BoundNotificationMethod> =
  MethodParamsByName[M] extends undefined
    ? { "method": M; "params"?: never }
    : { "method": M; "params": MethodParamsByName[M] };

export type BoundResponse<M extends keyof MethodResultsByName> =
  | { "id": RequestID; "result": MethodResultsByName[M]; "error"?: never }
  | { "id": RequestID; "result"?: never; "error": Error };

